section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/k8s-security-hardening.json",
  "type": "object",
  "required": [
    "namespace",
    "pod_security_enforce",
    "network_policy_default_deny",
    "container_hardening",
    "image_policy",
    "owner",
    "produced_at"
  ],
  "properties": {
    "namespace": {
      "type": "string",
      "pattern": "^[a-z][a-z0-9-]+$"
    },
    "pod_security_enforce": {
      "enum": [
        "restricted",
        "baseline",
        "privileged"
      ]
    },
    "network_policy_default_deny": {
      "type": "boolean",
      "const": true
    },
    "container_hardening": {
      "type": "object",
      "required": [
        "run_as_non_root",
        "read_only_root_fs",
        "drop_capabilities",
        "no_new_privileges"
      ],
      "properties": {
        "run_as_non_root": {
          "type": "boolean",
          "const": true
        },
        "read_only_root_fs": {
          "type": "boolean",
          "const": true
        },
        "drop_capabilities": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "minItems": 1
        },
        "no_new_privileges": {
          "type": "boolean",
          "const": true
        }
      }
    },
    "image_policy": {
      "type": "object",
      "required": [
        "engine",
        "signed_images_only"
      ],
      "properties": {
        "engine": {
          "enum": [
            "kyverno",
            "opa-gatekeeper"
          ]
        },
        "signed_images_only": {
          "type": "boolean",
          "const": true
        }
      }
    },
    "owner": {
      "type": "object",
      "required": [
        "name",
        "role"
      ],
      "properties": {
        "name": {
          "type": "string"
        },
        "role": {
          "type": "string"
        }
      }
    },
    "produced_at": {
      "type": "string",
      "format": "date-time"
    }
  },
  "additionalProperties": true
}

example.code:
{
  "namespace": "acme-prod",
  "pod_security_enforce": "restricted",
  "network_policy_default_deny": true,
  "container_hardening": {
    "run_as_non_root": true,
    "read_only_root_fs": true,
    "drop_capabilities": [
      "ALL"
    ],
    "no_new_privileges": true
  },
  "image_policy": {
    "engine": "kyverno",
    "signed_images_only": true
  },
  "owner": {
    "name": "Olena Boyko",
    "role": "head of security"
  },
  "produced_at": "2026-05-23T10:00:00Z"
}
